from ..core.pipeline import PipelineStep
from pathlib import Path
from typing import List, Dict, Any, Optional
import json

class QuestionGenerationStep(PipelineStep):
    def __init__(self, config: Dict[str, Any]):
        super().__init__("question_generation", config)

    def get_command(self, run_dir: Path) -> List[str]:
        script_path = "benchmark/scripts/evaluation/question_generation/generate_questions.py"
        
        # We use the merged scene graphs with attributes generated by prompt step
        sg_with_attributes = run_dir / "sg_with_attributes"
        
        out_dir = run_dir / "vqa_questions"
        output_questions_file = out_dir / "generated_questions.json"
        
        metadata_file = "benchmark/configs/vqa_metadata.json"
        synonyms_json = "benchmark/configs/vqa_synonyms.json"
        template_dir = "benchmark/scripts/evaluation/question_generation/templates"

        cmd = ["python", script_path, 
               "--validated_relations_dir", str(sg_with_attributes),
               "--metadata_file", metadata_file,
               "--synonyms_json", synonyms_json,
               "--template_dir", template_dir,
               "--output_questions_file", str(output_questions_file)]
               
        # Optional: Add refinement or multiple choice based on config
        if self.config.get("multiple_choice_method"):
             cmd.append("--multiple_choice_method")
        
        if self.config.get("refine_questions"):
             cmd.append("--refine")
             if "llm_judge" in self.config and "model" in self.config["llm_judge"]:
                 cmd.extend(["--refiner_model", self.config["llm_judge"]["model"]])
             
        return cmd

    def get_resources(self) -> Dict[str, Any]:
        return self.get_slurm_config()

class SceneGraphEvalStep(PipelineStep):
    def __init__(self, config: Dict[str, Any], model_name: Optional[str] = None):
        name = "scene_graph_eval"
        if model_name:
            name = f"scene_graph_eval_{model_name}"
        super().__init__(name, config)
        self.model_name = model_name

    def get_command(self, run_dir: Path) -> List[str]:
        script_path = "benchmark/scripts/evaluation/image_generation_eval.py"
        
        # Determine the target directories based on the model name
        base_sg_dir = run_dir / "final_graphs_pt" / (self.model_name or "default")
        
        matched_graphs = base_sg_dir / "scene_graphs_matched.json"
        matching_graphs = base_sg_dir / "scene_graphs_for_matching.json"
        pred_sg_dir = base_sg_dir / "injected_pred"
        output_jsonl = base_sg_dir / f"ige_answers_{self.model_name}.jsonl"
        questions_file = self.config.get('questions_file', str(run_dir / "vqa_questions" / "generated_questions.json"))

        cmd = ["python", script_path, 
               "--questions", str(questions_file),
               "--matched-graphs", str(matched_graphs),
               "--matching-graphs", str(matching_graphs),
               "--pred-sg-dir", str(pred_sg_dir),
               "--output", str(output_jsonl)]
               
        return cmd

    def get_resources(self) -> Dict[str, Any]:
        return self.get_slurm_config()

class VQAGenerationStep(PipelineStep):
    def __init__(self, config: Dict[str, Any], model_name: str, split_index: int = 0, num_splits: int = 1):
        name = f"vqa_generation_{model_name}"
        if num_splits > 1:
            name += f"_split_{split_index}"
        super().__init__(name, config)
        self.model_name = model_name
        self.split_index = split_index
        self.num_splits = num_splits

    def get_command(self, run_dir: Path) -> List[str]:
        script_path = "benchmark/scripts/evaluation/run_vqa_benchmark.py"
        questions_file = run_dir / "vqa_questions" / "generated_questions.json"
        img_dir = run_dir / "7_images" / self.model_name
        out_dir = run_dir / "vqa_outputs" / self.model_name / f"chunk_{self.split_index}"
        
        # Get shared model config from top-level
        shared_cfg = self.config.get('shared_model_config', {})
        
        cmd = ["python", script_path,
               "--generated_questions", str(questions_file),
               "--image_dir", str(img_dir),
               "--output_dir", str(out_dir),
               "--models", self.model_name,
               "--batch_size", str(self.config.get('batch_size', 1)),
               "--chunk_index", str(self.split_index),
               "--num_chunks", str(self.num_splits),
               "--shared_model_config", json.dumps(shared_cfg)]
                
        return cmd

    def get_resources(self) -> Dict[str, Any]:
        return self.get_slurm_config()

class VQAMergeStep(PipelineStep):
    def __init__(self, config: Dict[str, Any], model_name: str):
        name = f"vqa_merge_{model_name}"
        super().__init__(name, config)
        self.model_name = model_name

    def get_command(self, run_dir: Path) -> List[str]:
        script_path = "benchmark/scripts/evaluation/merge_results.py"
        out_base = run_dir / "vqa_outputs" / self.model_name
        merged_output = out_base / f"merged_{self.model_name}.jsonl"

        gt_index_pattern = str(out_base / "chunk_*/gt_index.jsonl")
        pred_files_pattern = str(out_base / f"chunk_*/{self.model_name}_answers.gpu*.jsonl")

        cmd = ["python", script_path,
               "--gt_index", gt_index_pattern,
               "--pred_files", pred_files_pattern,
               "--output", str(merged_output)]
                
        return cmd

    def get_resources(self) -> Dict[str, Any]:
        return self.get_slurm_config()

class LLMJudgeStep(PipelineStep):
    def __init__(self, config: Dict[str, Any], model_name: str, eval_type: str = "sg"):
        # eval_type is either 'sg' (scene graph) or 'vqa'
        name = f"llm_judge_{eval_type}_{model_name}"
        super().__init__(name, config)
        self.model_name = model_name
        self.eval_type = eval_type

    def get_command(self, run_dir: Path) -> List[str]:
        script_path = "benchmark/scripts/evaluation/llm_judge.py"
        llm_model = self.config.get("llm_judge", {}).get("model", "Qwen/Qwen3-VL-235B-A22B-Instruct")
        num_gpus = self.config.get("llm_judge", {}).get("slurm", {}).get("gpus", 8)
        
        if self.eval_type == "sg":
            base_dir = run_dir / "final_graphs_pt" / (self.model_name or "default")
            pred_jsonl = base_dir / f"ige_answers_{self.model_name}.jsonl"
            out_scored = base_dir / f"ige_scored_{self.model_name}.jsonl"
            out_metrics = base_dir / f"ige_metrics_{self.model_name}.json"
        else: # vqa
            base_dir = run_dir / "vqa_outputs" / self.model_name
            pred_jsonl = base_dir / f"merged_{self.model_name}.jsonl"
            out_scored = base_dir / f"scored_{self.model_name}.jsonl"
            out_metrics = base_dir / f"metrics_{self.model_name}.json"

        cmd = ["python", script_path,
               "--pred_jsonl", str(pred_jsonl),
               "--out_scored_jsonl", str(out_scored),
               "--out_metrics", str(out_metrics),
               "--model", llm_model,
               "--num_gpus", str(num_gpus),
               "--mode", "local"]
                
        return cmd

    def get_resources(self) -> Dict[str, Any]:
        return self.config.get('llm_judge', {}).get('slurm', self.config.get('slurm', {}))
